Your discount code logic likely has critical business logic flaws that attackers can exploit to get unauthorized discounts or even negative totals (resulting in credits/refunds). This mirrors the 2023 Revolut incident where improper state validation cost $23 million.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const app = express();
app.use(express.json());

// In-memory cart storage (simplified)
const carts = new Map();
const discountCodes = {
  'SAVE10': { percent: 10, minOrder: 50 },
  'SAVE25': { percent: 25, minOrder: 100 },
  'FREESHIP': { type: 'shipping', value: 0 }
};

app.post('/api/cart/:cartId/apply-discount', (req, res) => {
  const { cartId } = req.params;
  const { code } = req.body;

  const cart = carts.get(cartId);
  if (!cart) return res.status(404).json({ error: 'Cart not found' });

  const discount = discountCodes[code.toUpperCase()];
  if (!discount) return res.status(400).json({ error: 'Invalid code' });

  // FLAW 1: No check if discount already applied
  // FLAW 2: No check for minimum order after discount
  // FLAW 3: Discount applied to already-discounted total

  if (discount.percent) {
    cart.discount = (cart.discount || 0) + discount.percent;
    cart.total = cart.subtotal * (1 - cart.discount / 100);
  }

  // FLAW 4: No validation that total can't go negative
  cart.appliedCodes = cart.appliedCodes || [];
  cart.appliedCodes.push(code);

  res.json({ cart, message: 'Discount applied!' });
});

app.post('/api/cart/:cartId/checkout', (req, res) => {
  const cart = carts.get(req.params.cartId);

  // FLAW 5: No re-validation of business rules at checkout
  // FLAW 6: Price from client-side cart not verified against server
  processPayment(cart.total); // Could be negative!

  res.json({ success: true, charged: cart.total });
});
```

**Attack Payload**:
```bash
# Apply same discount code multiple times
curl -X POST http://localhost:3000/api/cart/abc123/apply-discount \
  -H "Content-Type: application/json" \
  -d '{"code": "SAVE25"}'

# Repeat 5 times to get 125% discount (negative total = store owes customer)
curl -X POST http://localhost:3000/api/cart/abc123/apply-discount \
  -H "Content-Type: application/json" \
  -d '{"code": "SAVE25"}'
```

**Why This Is Dangerous**:
- Discount codes can be stacked infinitely, exceeding 100% off
- No server-side validation of cart state before checkout
- Minimum order requirements not re-validated after discounts
- Race conditions allow multiple simultaneous discount applications
- Negative totals could trigger refunds instead of charges

**SECURE VERSION**:

```javascript
const express = require('express');
const app = express();
app.use(express.json());

const carts = new Map();
const discountCodes = {
  'SAVE10': { percent: 10, minOrder: 50, stackable: false, maxUses: 1 },
  'SAVE25': { percent: 25, minOrder: 100, stackable: false, maxUses: 1 },
  'FREESHIP': { type: 'shipping', value: 0, stackable: true, maxUses: 1 }
};

// Centralized cart calculation - single source of truth
function calculateCartTotal(cart) {
  let subtotal = cart.items.reduce((sum, item) => {
    // Always use server-side prices, never trust client
    const serverPrice = getProductPrice(item.productId);
    return sum + (serverPrice * item.quantity);
  }, 0);

  let discountAmount = 0;
  let maxDiscountPercent = 0;

  // Calculate maximum single discount (no stacking percentage discounts)
  for (const code of cart.appliedCodes || []) {
    const discount = discountCodes[code];
    if (discount && discount.percent) {
      maxDiscountPercent = Math.max(maxDiscountPercent, discount.percent);
    }
  }

  // Apply maximum percentage discount (capped at 50%)
  const cappedDiscount = Math.min(maxDiscountPercent, 50);
  discountAmount = subtotal * (cappedDiscount / 100);

  const total = Math.max(subtotal - discountAmount, 0.01); // Never below $0.01

  return {
    subtotal: Math.round(subtotal * 100) / 100,
    discountAmount: Math.round(discountAmount * 100) / 100,
    discountPercent: cappedDiscount,
    total: Math.round(total * 100) / 100
  };
}

app.post('/api/cart/:cartId/apply-discount', async (req, res) => {
  const { cartId } = req.params;
  const { code } = req.body;
  const userId = req.user.id; // From authentication middleware

  const cart = carts.get(cartId);
  if (!cart || cart.userId !== userId) {
    return res.status(404).json({ error: 'Cart not found' });
  }

  const normalizedCode = code.toUpperCase().trim();
  const discount = discountCodes[normalizedCode];

  if (!discount) {
    return res.status(400).json({ error: 'Invalid discount code' });
  }

  // Check if code already applied
  if (cart.appliedCodes?.includes(normalizedCode)) {
    return res.status(400).json({ error: 'Discount code already applied' });
  }

  // Check if non-stackable percentage discount already exists
  if (discount.percent && !discount.stackable) {
    const hasPercentDiscount = cart.appliedCodes?.some(c => 
      discountCodes[c]?.percent && !discountCodes[c]?.stackable
    );
    if (hasPercentDiscount) {
      return res.status(400).json({ 
        error: 'Cannot combine with existing percentage discount' 
      });
    }
  }

  // Calculate current totals to validate minimum order
  const currentCalc = calculateCartTotal(cart);
  if (discount.minOrder && currentCalc.subtotal < discount.minOrder) {
    return res.status(400).json({ 
      error: `Minimum order of $${discount.minOrder} required` 
    });
  }

  // Apply discount
  cart.appliedCodes = cart.appliedCodes || [];
  cart.appliedCodes.push(normalizedCode);

  // Recalculate with new discount
  const finalCalc = calculateCartTotal(cart);
  cart.calculatedTotal = finalCalc.total;

  res.json({ 
    cart: { ...cart, calculated: finalCalc },
    message: 'Discount applied successfully'
  });
});
```

**Key Security Controls**:
- **Single source of truth**: `calculateCartTotal()` always recalculates from server-side prices
- **Maximum discount cap**: Percentage discounts capped at 50% to prevent over-discount
- **Non-stackable enforcement**: Only one percentage discount allowed
- **Minimum total floor**: Cart total can never go below $0.01
- **Ownership validation**: Cart must belong to authenticated user

Excellent security thinking! Race conditions are exactly how Revolut lost $23M - attackers exploited timing windows in concurrent requests. You need atomic operations and idempotency for discounts, plus complete server-side re-validation at checkout.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const Redis = require('ioredis');
const crypto = require('crypto');
const { v4: uuidv4 } = require('uuid');

const app = express();
app.use(express.json());

const redis = new Redis(process.env.REDIS_URL);
const CART_LOCK_TTL = 5000; // 5 second lock
const DISCOUNT_LOCK_TTL = 10000; // 10 second lock

// Distributed lock to prevent race conditions
async function acquireLock(lockKey, ttl = CART_LOCK_TTL) {
  const lockValue = uuidv4();
  const acquired = await redis.set(
    `lock:${lockKey}`,
    lockValue,
    'PX', ttl,
    'NX' // Only set if not exists
  );
  return acquired ? lockValue : null;
}

async function releaseLock(lockKey, lockValue) {
  // Lua script ensures atomic check-and-delete
  const script = `
    if redis.call('get', KEYS[1]) == ARGV[1] then
      return redis.call('del', KEYS[1])
    else
      return 0
    end
  `;
  await redis.eval(script, 1, `lock:${lockKey}`, lockValue);
}

// Idempotency key validation
async function checkIdempotency(idempotencyKey, operation) {
  const existing = await redis.get(`idempotency:${idempotencyKey}`);
  if (existing) {
    return JSON.parse(existing); // Return cached result
  }
  return null;
}

async function saveIdempotency(idempotencyKey, result, ttl = 86400) {
  await redis.setex(
    `idempotency:${idempotencyKey}`,
    ttl,
    JSON.stringify(result)
  );
}

// Secure discount application with race condition protection
app.post('/api/cart/:cartId/apply-discount', async (req, res) => {
  const { cartId } = req.params;
  const { code } = req.body;
  const idempotencyKey = req.headers['idempotency-key'];
  const userId = req.user.id;

  // Require idempotency key for discount operations
  if (!idempotencyKey) {
    return res.status(400).json({ 
      error: 'Idempotency-Key header required' 
    });
  }

  // Check for duplicate request
  const cachedResult = await checkIdempotency(idempotencyKey);
  if (cachedResult) {
    console.log(`Idempotent request detected: ${idempotencyKey}`);
    return res.status(cachedResult.status).json(cachedResult.body);
  }

  // Acquire exclusive lock on cart
  const lockKey = `cart:${cartId}:discount`;
  const lockValue = await acquireLock(lockKey, DISCOUNT_LOCK_TTL);

  if (!lockValue) {
    // Another request is modifying this cart
    return res.status(429).json({ 
      error: 'Cart is being modified. Please retry.',
      retryAfter: 2
    });
  }

  try {
    // Fetch cart with version for optimistic locking
    const cart = await getCartWithVersion(cartId, userId);
    if (!cart) {
      const result = { status: 404, body: { error: 'Cart not found' } };
      await saveIdempotency(idempotencyKey, result);
      return res.status(404).json(result.body);
    }

    // Validate and apply discount
    const validationResult = await validateAndApplyDiscount(cart, code, userId);

    if (!validationResult.success) {
      const result = { status: 400, body: { error: validationResult.error } };
      await saveIdempotency(idempotencyKey, result);
      return res.status(400).json(result.body);
    }

    // Save with version check (optimistic locking)
    const saved = await saveCartWithVersionCheck(
      cart.id,
      validationResult.cart,
      cart.version
    );

    if (!saved) {
      // Concurrent modification detected
      return res.status(409).json({ 
        error: 'Cart was modified. Please refresh and retry.' 
      });
    }

    // Audit log
    await logDiscountApplication({
      cartId,
      userId,
      code,
      discountAmount: validationResult.discountAmount,
      timestamp: new Date().toISOString(),
      ipAddress: req.ip,
      userAgent: req.headers['user-agent']
    });

    const result = { 
      status: 200, 
      body: { 
        cart: validationResult.cart,
        message: 'Discount applied successfully'
      }
    };
    await saveIdempotency(idempotencyKey, result);
    return res.json(result.body);

  } finally {
    // Always release lock
    await releaseLock(lockKey, lockValue);
  }
});

// SECURE CHECKOUT - Complete re-validation
app.post('/api/cart/:cartId/checkout', async (req, res) => {
  const { cartId } = req.params;
  const { paymentToken } = req.body;
  const userId = req.user.id;
  const checkoutId = uuidv4();

  // Acquire exclusive checkout lock
  const lockValue = await acquireLock(`checkout:${cartId}`, 30000);
  if (!lockValue) {
    return res.status(429).json({ error: 'Checkout in progress' });
  }

  try {
    // CRITICAL: Complete server-side recalculation
    const cart = await getCartWithVersion(cartId, userId);
    if (!cart) {
      return res.status(404).json({ error: 'Cart not found' });
    }

    // Validate cart hasn't already been checked out
    if (cart.status !== 'active') {
      return res.status(400).json({ 
        error: 'Cart is no longer available for checkout' 
      });
    }

    // Re-validate all items are still available and prices match
    const itemValidation = await validateCartItems(cart.items);
    if (!itemValidation.valid) {
      return res.status(400).json({ 
        error: 'Some items are unavailable or prices changed',
        details: itemValidation.issues
      });
    }

    // Re-validate all discount codes are still valid
    const discountValidation = await revalidateDiscounts(
      cart.appliedCodes,
      cart.subtotal,
      userId
    );

    // CRITICAL: Use server-calculated total, NEVER trust client
    const serverCalculatedTotal = calculateSecureTotal(
      itemValidation.items,
      discountValidation.validDiscounts
    );

    // Mark cart as processing BEFORE charging
    await updateCartStatus(cartId, 'processing', cart.version);

    // Process payment with server-calculated amount
    const paymentResult = await processPaymentSecure({
      amount: serverCalculatedTotal.total,
      currency: 'USD',
      paymentToken,
      metadata: {
        checkoutId,
        cartId,
        userId,
        itemCount: cart.items.length
      }
    });

    if (!paymentResult.success) {
      await updateCartStatus(cartId, 'active', cart.version + 1);
      return res.status(402).json({ error: 'Payment failed' });
    }

    // Create order record
    const order = await createOrder({
      checkoutId,
      cartId,
      userId,
      items: itemValidation.items,
      discounts: discountValidation.validDiscounts,
      subtotal: serverCalculatedTotal.subtotal,
      discountAmount: serverCalculatedTotal.discountAmount,
      total: serverCalculatedTotal.total,
      paymentId: paymentResult.paymentId,
      status: 'confirmed'
    });

    // Mark cart as completed
    await updateCartStatus(cartId, 'completed', cart.version + 1);

    // Audit log for compliance
    await logCheckout({
      checkoutId,
      orderId: order.id,
      userId,
      total: serverCalculatedTotal.total,
      timestamp: new Date().toISOString(),
      ipAddress: req.ip
    });

    return res.json({
      success: true,
      orderId: order.id,
      charged: serverCalculatedTotal.total
    });

  } finally {
    await releaseLock(`checkout:${cartId}`, lockValue);
  }
});

// Secure total calculation - defense in depth
function calculateSecureTotal(items, discounts) {
  // Use Decimal.js or similar for financial calculations
  let subtotal = items.reduce((sum, item) => {
    // CRITICAL: Use server-side price lookup
    const serverPrice = item.serverVerifiedPrice;
    const quantity = Math.min(Math.max(1, item.quantity), 100); // Cap quantity
    return sum + (serverPrice * quantity);
  }, 0);

  // Calculate discount with multiple caps
  let totalDiscountPercent = 0;
  for (const discount of discounts) {
    if (discount.percent) {
      totalDiscountPercent += discount.percent;
    }
  }

  // BUSINESS RULE: Maximum 60% discount ever
  const cappedDiscountPercent = Math.min(totalDiscountPercent, 60);
  const discountAmount = subtotal * (cappedDiscountPercent / 100);

  // BUSINESS RULE: Minimum charge of $1.00
  const total = Math.max(subtotal - discountAmount, 1.00);

  // Round to cents (avoid floating point issues)
  return {
    subtotal: Math.round(subtotal * 100) / 100,
    discountAmount: Math.round(discountAmount * 100) / 100,
    discountPercent: cappedDiscountPercent,
    total: Math.round(total * 100) / 100
  };
}
```

**Defense in Depth Layers**:

1. **Distributed Locking** - Prevents race conditions:
```javascript
// Redis-based lock with automatic expiration
const lockValue = await acquireLock(`cart:${cartId}:discount`, 10000);
if (!lockValue) {
  return res.status(429).json({ error: 'Please retry' });
}
```

2. **Idempotency Keys** - Prevents duplicate processing:
```javascript
// Same request = same result
const cached = await checkIdempotency(idempotencyKey);
if (cached) return res.status(cached.status).json(cached.body);
```

3. **Optimistic Locking** - Detects concurrent modifications:
```javascript
// Version check on save
const saved = await saveCartWithVersionCheck(cartId, cart, expectedVersion);
if (!saved) return res.status(409).json({ error: 'Concurrent modification' });
```

**Additional Protections**:
- **Server-side price verification**: Never trust client-submitted prices
- **Maximum discount caps**: Both per-code (50%) and total (60%)
- **Minimum charge floor**: $1.00 minimum prevents negative totals
- **Cart status state machine**: active → processing → completed (no rollback)
- **Comprehensive audit logging**: All discount and checkout operations logged
- **Rate limiting**: Prevent brute-force discount code guessing
- **Quantity caps**: Maximum 100 of any item to prevent overflow attacks

Your funds transfer implementation likely has critical business logic vulnerabilities. The 2023 Revolut incident resulted in $20 million stolen through similar payment logic flaws. Let me show you common vulnerable patterns and how to fix them.

**VULNERABLE CODE**:

```java
import java.sql.*;
import javax.servlet.http.*;
import java.math.BigDecimal;

public class TransferService {
    private static final String DB_URL = "jdbc:postgresql://localhost/banking";
    private static final String USER = "dbuser";
    private static final String PASS = "dbpass";

    public boolean transferFunds(long fromAccountId, long toAccountId, 
                                  BigDecimal amount, long userId) {
        try (Connection conn = DriverManager.getConnection(DB_URL, USER, PASS)) {
            // VULNERABLE: No transaction isolation
            // VULNERABLE: No balance check before debit
            // VULNERABLE: No ownership verification

            // Debit from source account
            String debitSql = "UPDATE accounts SET balance = balance - ? WHERE id = ?";
            PreparedStatement debitStmt = conn.prepareStatement(debitSql);
            debitStmt.setBigDecimal(1, amount);
            debitStmt.setLong(2, fromAccountId);
            debitStmt.executeUpdate();

            // Credit to destination account
            String creditSql = "UPDATE accounts SET balance = balance + ? WHERE id = ?";
            PreparedStatement creditStmt = conn.prepareStatement(creditSql);
            creditStmt.setBigDecimal(1, amount);
            creditStmt.setLong(2, toAccountId);
            creditStmt.executeUpdate();

            return true;
        } catch (SQLException e) {
            e.printStackTrace();
            return false;
        }
    }

    // VULNERABLE: Negative amount allows reverse transfer
    public boolean processRefund(long transactionId, long userId) {
        try (Connection conn = DriverManager.getConnection(DB_URL, USER, PASS)) {
            String sql = "SELECT from_account, to_account, amount FROM transactions WHERE id = ?";
            PreparedStatement stmt = conn.prepareStatement(sql);
            stmt.setLong(1, transactionId);
            ResultSet rs = stmt.executeQuery();

            if (rs.next()) {
                // VULNERABLE: No check if refund already processed
                // VULNERABLE: No ownership verification
                return transferFunds(rs.getLong("to_account"), 
                                    rs.getLong("from_account"), 
                                    rs.getBigDecimal("amount"), userId);
            }
            return false;
        } catch (SQLException e) {
            return false;
        }
    }
}
```

**Attack Payload**:
```text
1. Race Condition Attack:
   - Send 10 concurrent transfer requests for $1000 from account with $1000 balance
   - Due to lack of proper locking, all 10 may succeed = $10,000 transferred

2. Negative Amount Attack:
   - POST /api/transfer {from: 123, to: 456, amount: -500}
   - Reverses the transfer direction, stealing from destination account

3. Double Refund Attack:
   - Request refund for transaction #789
   - Immediately request refund again before first completes
   - Receive refund twice

4. IDOR Attack:
   - Transfer from account 999 (not owned by user) to attacker's account
```

**Why This Is Dangerous**:
- No transaction isolation allows race conditions (double-spending)
- No balance verification before debit allows negative balances
- No amount validation allows negative transfer amounts
- No account ownership verification enables unauthorized transfers
- No refund idempotency allows double refunds
- No audit trail for forensic investigation

**SECURE VERSION**:

```java
import java.sql.*;
import java.math.BigDecimal;
import java.util.UUID;
import java.util.logging.Logger;

public class SecureTransferService {
    private static final Logger logger = Logger.getLogger(SecureTransferService.class.getName());
    private static final String DB_URL = "jdbc:postgresql://localhost/banking";
    private static final String USER = "dbuser";
    private static final String PASS = "dbpass";
    private static final BigDecimal MAX_TRANSFER_AMOUNT = new BigDecimal("50000.00");
    private static final BigDecimal MIN_TRANSFER_AMOUNT = new BigDecimal("0.01");

    public TransferResult transferFunds(TransferRequest request, long authenticatedUserId) 
            throws TransferException {

        String idempotencyKey = request.getIdempotencyKey();

        // INPUT VALIDATION: Amount bounds checking
        if (request.getAmount().compareTo(MIN_TRANSFER_AMOUNT) < 0) {
            throw new TransferException("Amount must be positive");
        }
        if (request.getAmount().compareTo(MAX_TRANSFER_AMOUNT) > 0) {
            throw new TransferException("Amount exceeds maximum transfer limit");
        }
        if (request.getFromAccountId() == request.getToAccountId()) {
            throw new TransferException("Cannot transfer to same account");
        }

        Connection conn = null;
        try {
            conn = DriverManager.getConnection(DB_URL, USER, PASS);
            conn.setAutoCommit(false);
            conn.setTransactionIsolation(Connection.TRANSACTION_SERIALIZABLE);

            // IDEMPOTENCY CHECK: Prevent duplicate processing
            if (isIdempotencyKeyUsed(conn, idempotencyKey)) {
                return getPreviousResult(conn, idempotencyKey);
            }

            // OWNERSHIP VERIFICATION: User must own source account
            if (!verifyAccountOwnership(conn, request.getFromAccountId(), authenticatedUserId)) {
                logger.warning("Unauthorized transfer attempt: User " + authenticatedUserId + 
                              " tried to access account " + request.getFromAccountId());
                throw new TransferException("Unauthorized: You don't own this account");
            }

            // BALANCE CHECK WITH LOCK: Prevent race conditions
            BigDecimal currentBalance = getBalanceWithLock(conn, request.getFromAccountId());
            if (currentBalance.compareTo(request.getAmount()) < 0) {
                throw new TransferException("Insufficient funds");
            }

            // VERIFY DESTINATION EXISTS
            if (!accountExists(conn, request.getToAccountId())) {
                throw new TransferException("Destination account not found");
            }

            // ATOMIC TRANSFER: Debit and credit in single transaction
            String transactionId = UUID.randomUUID().toString();

            executeDebit(conn, request.getFromAccountId(), request.getAmount());
            executeCredit(conn, request.getToAccountId(), request.getAmount());

            // AUDIT TRAIL: Record transaction details
            recordTransaction(conn, transactionId, request, authenticatedUserId);
            recordIdempotencyKey(conn, idempotencyKey, transactionId);

            conn.commit();

            logger.info("Transfer completed: " + transactionId + " Amount: " + request.getAmount());

            return new TransferResult(transactionId, TransferStatus.SUCCESS);

        } catch (SQLException e) {
            if (conn != null) {
                try { conn.rollback(); } catch (SQLException ex) { }
            }
            logger.severe("Transfer failed: " + e.getMessage());
            throw new TransferException("Transfer failed - please retry");
        } finally {
            if (conn != null) {
                try { conn.close(); } catch (SQLException e) { }
            }
        }
    }

    private BigDecimal getBalanceWithLock(Connection conn, long accountId) throws SQLException {
        // SELECT FOR UPDATE provides row-level locking
        String sql = "SELECT balance FROM accounts WHERE id = ? FOR UPDATE";
        try (PreparedStatement stmt = conn.prepareStatement(sql)) {
            stmt.setLong(1, accountId);
            ResultSet rs = stmt.executeQuery();
            if (rs.next()) {
                return rs.getBigDecimal("balance");
            }
            throw new SQLException("Account not found");
        }
    }

    private boolean verifyAccountOwnership(Connection conn, long accountId, long userId) 
            throws SQLException {
        String sql = "SELECT 1 FROM accounts WHERE id = ? AND owner_id = ?";
        try (PreparedStatement stmt = conn.prepareStatement(sql)) {
            stmt.setLong(1, accountId);
            stmt.setLong(2, userId);
            return stmt.executeQuery().next();
        }
    }
}
```

**Key Security Controls**:
- **SERIALIZABLE isolation**: Prevents race conditions through strict transaction ordering
- **SELECT FOR UPDATE**: Row-level locking prevents concurrent modifications
- **Ownership verification**: Ensures user can only transfer from their own accounts
- **Amount validation**: Prevents negative amounts and enforces limits
- **Idempotency keys**: Prevents duplicate transaction processing
- **Complete audit trail**: Records all transfers for forensic analysis

Complex business logic introduces many abuse vectors. The 2022 Uber Eats promotion abuse cost $65M+ when attackers exploited referral and discount stacking flaws. Here's a production-ready pattern for multi-layer business logic protection.

**PRODUCTION PATTERN**:

```java
import java.sql.*;
import java.math.BigDecimal;
import java.time.Instant;
import java.time.Duration;
import java.util.*;
import java.util.concurrent.ConcurrentHashMap;
import java.util.logging.Logger;

public class SecureOrderService {
    private static final Logger logger = Logger.getLogger(SecureOrderService.class.getName());
    private static final Logger auditLogger = Logger.getLogger("AUDIT." + SecureOrderService.class.getName());

    private final DataSource dataSource;
    private final RateLimiter rateLimiter;
    private final FraudDetectionService fraudService;
    private final Map<String, Instant> recentOrders = new ConcurrentHashMap<>();

    // Business rule constants
    private static final int MAX_PROMOTIONS_PER_ORDER = 2;
    private static final BigDecimal MAX_DISCOUNT_PERCENTAGE = new BigDecimal("0.50");
    private static final BigDecimal MAX_POINTS_REDEMPTION_PER_ORDER = new BigDecimal("100.00");
    private static final Duration MIN_ORDER_INTERVAL = Duration.ofSeconds(30);

    public OrderResult processOrder(OrderRequest request, AuthenticatedUser user) 
            throws OrderException {

        String orderId = UUID.randomUUID().toString();

        // LAYER 1: Rate limiting per user
        if (!rateLimiter.tryAcquire("order:" + user.getId(), 10, Duration.ofMinutes(1))) {
            auditLogger.warning("Rate limit exceeded: User " + user.getId());
            throw new OrderException("Too many orders. Please wait.");
        }

        // LAYER 2: Velocity check - prevent rapid-fire orders
        Instant lastOrder = recentOrders.get(user.getId().toString());
        if (lastOrder != null && Duration.between(lastOrder, Instant.now()).compareTo(MIN_ORDER_INTERVAL) < 0) {
            auditLogger.warning("Velocity violation: User " + user.getId());
            throw new OrderException("Please wait before placing another order");
        }

        Connection conn = null;
        try {
            conn = dataSource.getConnection();
            conn.setAutoCommit(false);
            conn.setTransactionIsolation(Connection.TRANSACTION_SERIALIZABLE);

            // LAYER 3: Fraud scoring
            FraudScore score = fraudService.evaluate(request, user);
            if (score.getRiskLevel() == RiskLevel.HIGH) {
                auditLogger.severe("High fraud risk order blocked: " + orderId);
                throw new OrderException("Order could not be processed");
            }

            // Calculate order totals with business logic protection
            OrderCalculation calc = calculateOrderSecurely(conn, request, user);

            // LAYER 4: Sanity checks on final amounts
            validateOrderSanity(calc, request);

            // LAYER 5: Persist with full audit trail
            persistOrder(conn, orderId, calc, user);

            conn.commit();
            recentOrders.put(user.getId().toString(), Instant.now());

            auditLogger.info(String.format(
                "ORDER_COMPLETED|orderId=%s|userId=%s|subtotal=%.2f|discount=%.2f|final=%.2f|promos=%s",
                orderId, user.getId(), calc.getSubtotal(), calc.getTotalDiscount(), 
                calc.getFinalTotal(), calc.getAppliedPromotions()
            ));

            return new OrderResult(orderId, calc);

        } catch (SQLException e) {
            if (conn != null) {
                try { conn.rollback(); } catch (SQLException ex) { }
            }
            logger.severe("Order failed: " + e.getMessage());
            throw new OrderException("Order processing failed");
        } finally {
            if (conn != null) {
                try { conn.close(); } catch (SQLException e) { }
            }
        }
    }

    private OrderCalculation calculateOrderSecurely(Connection conn, OrderRequest request, 
            AuthenticatedUser user) throws SQLException, OrderException {

        OrderCalculation calc = new OrderCalculation();

        // Calculate base prices from database (never trust client prices)
        BigDecimal subtotal = calculateSubtotalFromDatabase(conn, request.getItems());
        calc.setSubtotal(subtotal);

        // PROMOTION VALIDATION
        List<String> appliedPromos = new ArrayList<>();
        BigDecimal totalDiscount = BigDecimal.ZERO;

        if (request.getPromotionCodes() != null) {
            // RULE: Limit number of promotions per order
            if (request.getPromotionCodes().size() > MAX_PROMOTIONS_PER_ORDER) {
                throw new OrderException("Maximum " + MAX_PROMOTIONS_PER_ORDER + " promotions per order");
            }

            for (String promoCode : request.getPromotionCodes()) {
                PromotionValidation validation = validatePromotion(conn, promoCode, user, subtotal);

                if (validation.isValid()) {
                    // Check for stacking rules
                    if (!canStackPromotion(appliedPromos, promoCode, conn)) {
                        auditLogger.warning("Promo stacking blocked: " + promoCode + " User: " + user.getId());
                        continue;
                    }

                    BigDecimal discount = validation.getDiscountAmount();

                    // RULE: Cap individual discount
                    BigDecimal maxDiscount = subtotal.multiply(MAX_DISCOUNT_PERCENTAGE);
                    if (discount.compareTo(maxDiscount) > 0) {
                        discount = maxDiscount;
                        auditLogger.info("Discount capped: " + promoCode);
                    }

                    totalDiscount = totalDiscount.add(discount);
                    appliedPromos.add(promoCode);

                    // Mark promotion as used (with FOR UPDATE lock)
                    markPromotionUsed(conn, promoCode, user.getId());
                }
            }
        }

        // RULE: Total discount cannot exceed percentage of subtotal
        BigDecimal maxTotalDiscount = subtotal.multiply(MAX_DISCOUNT_PERCENTAGE);
        if (totalDiscount.compareTo(maxTotalDiscount) > 0) {
            totalDiscount = maxTotalDiscount;
            auditLogger.warning("Total discount capped for user: " + user.getId());
        }

        calc.setTotalDiscount(totalDiscount);
        calc.setAppliedPromotions(appliedPromos);

        // LOYALTY POINTS REDEMPTION
        if (request.getRedeemPoints() != null && request.getRedeemPoints() > 0) {
            BigDecimal pointsValue = calculatePointsRedemption(conn, user, request.getRedeemPoints());

            // RULE: Cap points redemption per order
            if (pointsValue.compareTo(MAX_POINTS_REDEMPTION_PER_ORDER) > 0) {
                pointsValue = MAX_POINTS_REDEMPTION_PER_ORDER;
            }

            // RULE: Points cannot make order negative
            BigDecimal afterDiscount = subtotal.subtract(totalDiscount);
            if (pointsValue.compareTo(afterDiscount) > 0) {
                pointsValue = afterDiscount;
            }

            calc.setPointsRedemption(pointsValue);

            // Deduct points with lock to prevent race conditions
            deductLoyaltyPoints(conn, user.getId(), request.getRedeemPoints());
        }

        // Calculate final total
        BigDecimal finalTotal = subtotal
            .subtract(calc.getTotalDiscount())
            .subtract(calc.getPointsRedemption() != null ? calc.getPointsRedemption() : BigDecimal.ZERO);

        // RULE: Minimum order amount
        if (finalTotal.compareTo(new BigDecimal("0.01")) < 0) {
            finalTotal = new BigDecimal("0.01");
        }

        calc.setFinalTotal(finalTotal);
        return calc;
    }

    private PromotionValidation validatePromotion(Connection conn, String code, 
            AuthenticatedUser user, BigDecimal subtotal) throws SQLException {

        // Lock the promotion row to prevent race conditions
        String sql = """
            SELECT p.id, p.discount_type, p.discount_value, p.min_order_amount,
                   p.max_uses, p.current_uses, p.per_user_limit, p.valid_from, p.valid_until,
                   p.stackable, p.excluded_categories,
                   (SELECT COUNT(*) FROM promotion_uses WHERE promotion_id = p.id AND user_id = ?) as user_uses
            FROM promotions p 
            WHERE p.code = ? AND p.active = true
            FOR UPDATE
            """;

        try (PreparedStatement stmt = conn.prepareStatement(sql)) {
            stmt.setLong(1, user.getId());
            stmt.setString(2, code.toUpperCase().trim());
            ResultSet rs = stmt.executeQuery();

            if (!rs.next()) {
                return PromotionValidation.invalid("Promotion not found");
            }

            // Check validity period
            Timestamp validFrom = rs.getTimestamp("valid_from");
            Timestamp validUntil = rs.getTimestamp("valid_until");
            Timestamp now = new Timestamp(System.currentTimeMillis());

            if (now.before(validFrom) || now.after(validUntil)) {
                return PromotionValidation.invalid("Promotion expired or not yet active");
            }

            // Check global usage limit
            int maxUses = rs.getInt("max_uses");
            int currentUses = rs.getInt("current_uses");
            if (maxUses > 0 && currentUses >= maxUses) {
                return PromotionValidation.invalid("Promotion fully redeemed");
            }

            // Check per-user limit
            int perUserLimit = rs.getInt("per_user_limit");
            int userUses = rs.getInt("user_uses");
            if (perUserLimit > 0 && userUses >= perUserLimit) {
                auditLogger.warning("User exceeded promo limit: " + user.getId() + " Promo: " + code);
                return PromotionValidation.invalid("You have already used this promotion");
            }

            // Check minimum order amount
            BigDecimal minOrder = rs.getBigDecimal("min_order_amount");
            if (minOrder != null && subtotal.compareTo(minOrder) < 0) {
                return PromotionValidation.invalid("Minimum order amount not met");
            }

            // Calculate discount
            String discountType = rs.getString("discount_type");
            BigDecimal discountValue = rs.getBigDecimal("discount_value");
            BigDecimal discountAmount;

            if ("PERCENTAGE".equals(discountType)) {
                discountAmount = subtotal.multiply(discountValue.divide(new BigDecimal("100")));
            } else {
                discountAmount = discountValue;
            }

            return PromotionValidation.valid(rs.getLong("id"), discountAmount, rs.getBoolean("stackable"));
        }
    }

    private void validateOrderSanity(OrderCalculation calc, OrderRequest request) 
            throws OrderException {

        // SANITY CHECK: Discount should never exceed subtotal
        if (calc.getTotalDiscount().compareTo(calc.getSubtotal()) > 0) {
            auditLogger.severe("SANITY_VIOLATION: Discount > Subtotal");
            throw new OrderException("Order calculation error");
        }

        // SANITY CHECK: Final total should be positive
        if (calc.getFinalTotal().compareTo(BigDecimal.ZERO) < 0) {
            auditLogger.severe("SANITY_VIOLATION: Negative final total");
            throw new OrderException("Order calculation error");
        }

        // SANITY CHECK: Discount percentage within bounds
        BigDecimal discountPercentage = calc.getTotalDiscount()
            .divide(calc.getSubtotal(), 4, BigDecimal.ROUND_HALF_UP);
        if (discountPercentage.compareTo(MAX_DISCOUNT_PERCENTAGE) > 0) {
            auditLogger.severe("SANITY_VIOLATION: Discount percentage exceeded");
            throw new OrderException("Order calculation error");
        }
    }

    private BigDecimal calculatePointsRedemption(Connection conn, AuthenticatedUser user, 
            int pointsToRedeem) throws SQLException, OrderException {

        // Get current points balance with lock
        String sql = "SELECT points_balance FROM loyalty_accounts WHERE user_id = ? FOR UPDATE";
        try (PreparedStatement stmt = conn.prepareStatement(sql)) {
            stmt.setLong(1, user.getId());
            ResultSet rs = stmt.executeQuery();

            if (!rs.next()) {
                throw new OrderException("Loyalty account not found");
            }

            int currentBalance = rs.getInt("points_balance");
            if (pointsToRedeem > currentBalance) {
                throw new OrderException("Insufficient loyalty points");
            }

            // 100 points = $1 (server-side calculation, never trust client)
            return new BigDecimal(pointsToRedeem).divide(new BigDecimal("100"), 2, BigDecimal.ROUND_HALF_UP);
        }
    }

    private void deductLoyaltyPoints(Connection conn, long userId, int points) throws SQLException {
        String sql = """
            UPDATE loyalty_accounts 
            SET points_balance = points_balance - ?, 
                last_modified = CURRENT_TIMESTAMP 
            WHERE user_id = ? AND points_balance >= ?
            """;
        try (PreparedStatement stmt = conn.prepareStatement(sql)) {
            stmt.setInt(1, points);
            stmt.setLong(2, userId);
            stmt.setInt(3, points);
            int rows = stmt.executeUpdate();
            if (rows == 0) {
                throw new SQLException("Failed to deduct points - possible race condition");
            }
        }
    }
}
