**Why This Is Dangerous**:
- Discount codes can be stacked infinitely, reducing prices to zero or negative
- No validation that cart totals match server-calculated prices
- Race conditions allow duplicate refunds (seen in Revolut breach)
- Missing ownership checks allow refunding others' orders
- No audit trail for financial operations

**SECURE VERSION**:

```javascript
const express = require('express');
const { v4: uuidv4 } = require('uuid');
const Mutex = require('async-mutex').Mutex;

const app = express();
const orderMutexes = new Map();

class SecureCheckout {
  constructor(db, logger) {
    this.db = db;
    this.logger = logger;
  }

  async applyDiscount(userId, discountCode, sessionId) {
    const cart = await this.db.getCart(userId);

    // CONTROL 1: Check if any discount already applied
    if (cart.appliedDiscounts && cart.appliedDiscounts.length > 0) {
      this.logger.warn('Discount stacking attempt', { userId, sessionId });
      throw new Error('Only one discount code allowed per order');
    }

    // CONTROL 2: Validate discount code exists and is active
    const discount = await this.db.getValidDiscount(discountCode);
    if (!discount || discount.expiresAt < new Date()) {
      throw new Error('Invalid or expired discount code');
    }

    // CONTROL 3: Check discount usage limits
    const usageCount = await this.db.getDiscountUsage(discountCode, userId);
    if (usageCount >= discount.maxUsesPerUser) {
      throw new Error('Discount code usage limit reached');
    }

    // CONTROL 4: Recalculate total server-side
    const newTotal = this.calculateSecureTotal(cart, discount);

    // CONTROL 5: Ensure total is positive
    if (newTotal <= 0) {
      this.logger.alert('Negative total attempt', { userId, newTotal });
      throw new Error('Invalid cart total');
    }

    await this.db.updateCart(userId, {
      appliedDiscounts: [discountCode],
      total: newTotal,
      calculatedAt: new Date()
    });

    return { newTotal };
  }

  calculateSecureTotal(cart, discount) {
    // Server-side price calculation from product database
    let subtotal = 0;
    for (const item of cart.items) {
      const product = this.db.getProductSync(item.productId);
      // Use database price, not client-provided price
      subtotal += product.price * Math.max(0, Math.floor(item.quantity));
    }

    const discountAmount = Math.min(
      subtotal * (discount.percentage / 100),
      discount.maxDiscountAmount || Infinity
    );

    return Math.max(subtotal - discountAmount, 0.01); // Minimum 1 cent
  }

  async processCheckout(userId, paymentInfo, sessionId) {
    const cart = await this.db.getCart(userId);

    // CONTROL 6: Verify cart hasn't been tampered with
    const expectedTotal = this.calculateSecureTotal(
      cart,
      cart.appliedDiscounts?.[0] ? await this.db.getValidDiscount(cart.appliedDiscounts[0]) : null
    );

    if (Math.abs(cart.total - expectedTotal) > 0.01) {
      this.logger.alert('Price manipulation detected', {
        userId,
        cartTotal: cart.total,
        expectedTotal,
        sessionId
      });
      throw new Error('Cart validation failed. Please refresh and try again.');
    }

    // CONTROL 7: Idempotency key to prevent duplicate orders
    const idempotencyKey = `checkout-${userId}-${cart.checksum}`;
    const existingOrder = await this.db.getOrderByIdempotencyKey(idempotencyKey);
    if (existingOrder) {
      return { orderId: existingOrder.id, alreadyProcessed: true };
    }

    // Process payment and create order atomically
    return await this.db.transaction(async (tx) => {
      const orderId = uuidv4();

      const paymentResult = await this.paymentGateway.charge({
        amount: expectedTotal,
        idempotencyKey,
        metadata: { orderId, userId }
      });

      await tx.createOrder({
        id: orderId,
        userId,
        items: cart.items,
        total: expectedTotal,
        paymentId: paymentResult.id,
        idempotencyKey,
        status: 'paid',
        refundStatus: 'none',
        createdAt: new Date()
      });

      await tx.clearCart(userId);
      await tx.markDiscountUsed(cart.appliedDiscounts?.[0], userId);

      this.logger.info('Order completed', { orderId, userId, total: expectedTotal });

      return { orderId };
    });
  }
}
