**Key Security Controls**:
- **Single discount enforcement**: Prevents stacking multiple codes
- **Server-side price calculation**: Never trust client-provided prices
- **Positive total validation**: Prevents negative price exploits
- **Idempotency keys**: Prevents duplicate order/payment processing
- **Atomic transactions**: Ensures consistency between payment and order creation
- **Audit logging**: All financial operations are logged with session context

The refund race condition is exactly what caused the Revolut breach - attackers sent hundreds of concurrent refund requests before the database could update the order status. Here's a production-ready solution with multiple defense layers.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const { v4: uuidv4 } = require('uuid');
const Redis = require('ioredis');
const { Sequelize, Op } = require('sequelize');

const app = express();
const redis = new Redis(process.env.REDIS_URL);

class SecureRefundService {
  constructor(db, paymentGateway, logger, alertService) {
    this.db = db;
    this.paymentGateway = paymentGateway;
    this.logger = logger;
    this.alertService = alertService;
  }

  async processRefund(orderId, userId, requestId, ipAddress) {
    // LAYER 1: Distributed lock to prevent concurrent processing
    const lockKey = `refund-lock:${orderId}`;
    const lockAcquired = await redis.set(lockKey, requestId, 'NX', 'EX', 30);

    if (!lockAcquired) {
      this.logger.warn('Concurrent refund attempt blocked', {
        orderId,
        userId,
        requestId,
        ipAddress
      });
      throw new Error('Refund already in progress');
    }

    try {
      // LAYER 2: Database-level optimistic locking
      const order = await this.db.Order.findOne({
        where: { id: orderId },
        lock: Sequelize.Transaction.LOCK.UPDATE
      });

      // LAYER 3: Ownership verification
      if (!order || order.userId !== userId) {
        this.logger.alert('Unauthorized refund attempt', {
          orderId,
          requestingUser: userId,
          orderOwner: order?.userId,
          ipAddress
        });
        throw new Error('Order not found');
      }

      // LAYER 4: State machine validation
      const validRefundStates = ['paid', 'shipped', 'delivered'];
      if (!validRefundStates.includes(order.status)) {
        throw new Error(`Cannot refund order in ${order.status} status`);
      }

      if (order.refundStatus !== 'none') {
        this.logger.warn('Duplicate refund attempt', {
          orderId,
          currentRefundStatus: order.refundStatus,
          userId,
          ipAddress
        });
        throw new Error('Refund already processed or pending');
      }

      // LAYER 5: Idempotency check against refund history
      const existingRefund = await this.db.RefundLog.findOne({
        where: {
          orderId,
          status: { [Op.in]: ['pending', 'completed'] }
        }
      });

      if (existingRefund) {
        return {
          success: true,
          refundId: existingRefund.id,
          alreadyProcessed: true
        };
      }

      // LAYER 6: Atomic state transition with refund processing
      const refundResult = await this.db.sequelize.transaction(async (t) => {
        const refundId = uuidv4();

        // Create refund record FIRST (prevents race condition)
        await this.db.RefundLog.create({
          id: refundId,
          orderId,
          userId,
          amount: order.total,
          status: 'pending',
          requestId,
          ipAddress,
          createdAt: new Date()
        }, { transaction: t });

        // Update order status atomically
        const [updatedRows] = await this.db.Order.update(
          {
            refundStatus: 'pending',
            refundInitiatedAt: new Date(),
            refundRequestId: requestId
          },
          {
            where: {
              id: orderId,
              refundStatus: 'none' // Optimistic lock condition
            },
            transaction: t
          }
        );

        // CRITICAL: If no rows updated, another request won the race
        if (updatedRows === 0) {
          throw new Error('Refund state changed during processing');
        }

        // Process actual refund with payment provider
        const paymentRefund = await this.paymentGateway.refund({
          paymentId: order.paymentId,
          amount: order.total,
          idempotencyKey: `refund-${orderId}`,
          metadata: { orderId, refundId, userId }
        });

        // Update statuses to completed
        await this.db.RefundLog.update(
          {
            status: 'completed',
            paymentRefundId: paymentRefund.id,
            completedAt: new Date()
          },
          { where: { id: refundId }, transaction: t }
        );

        await this.db.Order.update(
          { refundStatus: 'completed' },
          { where: { id: orderId }, transaction: t }
        );

        return { refundId, paymentRefundId: paymentRefund.id };
      });

      // LAYER 7: Audit trail
      this.logger.info('Refund completed', {
        orderId,
        refundId: refundResult.refundId,
        amount: order.total,
        userId,
        requestId,
        ipAddress
      });

      return { success: true, ...refundResult };

    } finally {
      // Always release the lock
      await redis.del(lockKey);
    }
  }

  // LAYER 8: Anomaly detection for refund patterns
  async checkRefundAnomalies(userId, ipAddress) {
    const recentRefunds = await this.db.RefundLog.count({
      where: {
        userId,
        createdAt: { [Op.gte]: new Date(Date.now() - 24 * 60 * 60 * 1000) }
      }
    });

    if (recentRefunds >= 3) {
      this.alertService.notify('High refund frequency', {
        userId,
        refundCount: recentRefunds,
        ipAddress,
        severity: 'high'
      });
      return false; // Block refund, require manual review
    }

    const ipRefunds = await this.db.RefundLog.count({
      where: {
        ipAddress,
        createdAt: { [Op.gte]: new Date(Date.now() - 60 * 60 * 1000) }
      }
    });

    if (ipRefunds >= 5) {
      this.alertService.notify('Refund abuse from IP', {
        ipAddress,
        refundCount: ipRefunds,
        severity: 'critical'
      });
      return false;
    }

    return true;
  }
}

// Express route with all protections
app.post('/api/refund', async (req, res) => {
  const requestId = uuidv4();
  const ipAddress = req.ip;
  const userId = req.session.userId;
  const { orderId } = req.body;

  try {
    // Rate limit check
    const allowed = await refundService.checkRefundAnomalies(userId, ipAddress);
    if (!allowed) {
      return res.status(429).json({
        error: 'Too many refund requests. Please contact support.',
        supportTicket: await createSupportTicket(userId, orderId)
      });
    }

    const result = await refundService.processRefund(
      orderId,
      userId,
      requestId,
      ipAddress
    );

    res.json(result);
  } catch (error) {
    logger.error('Refund failed', {
      error: error.message,
      orderId,
      userId,
      requestId
    });
    res.status(400).json({ error: error.message });
  }
});
