// Server-side cart calculation (never trust client)
async function calculateCartTotal(userId, cartItems) {
  let total = 0;
  for (const item of cartItems) {
    const productPrice = await redis.hget(`product:${item.productId}`, 'price');
    if (!productPrice) {
