    const { userId } = req.body;
    const lockKey = `cart:lock:${userId}`;
    const lockValue = await lock.acquire(lockKey);

    if (!lockValue) {
      return res.status(429).json({ error: 'Please retry', retryAfter: 2 });
    }

    try {
      const cart = await redis.hgetall(`cart:${userId}`);
      const finalTotal = parseFloat(cart.currentTotal);

      // Final sanity checks
      if (isNaN(finalTotal) || finalTotal < 0.01) {
        console.log(`[SECURITY] Invalid checkout total for ${userId}: ${finalTotal}`);
        return res.status(400).json({ error: 'Invalid cart state' });
      }

      if (finalTotal > 1000000) {
        console.log(`[SECURITY] Suspicious checkout amount for ${userId}: ${finalTotal}`);
        return res.status(400).json({ error: 'Please contact support for large orders' });
      }

      // Process payment...
      res.json({ success: true, charged: finalTotal });

    } finally {
      await lock.release(lockKey, lockValue);
    }
  }
);
```

